import React, { useEffect, useRef } from 'react';
import './Hero.css';

const stats = [
  { label: '월간 대화 세션', value: 50000, suffix: '+', type: 'int' },
  { label: '사용자 만족도', value: 98, suffix: '%', type: 'int' },
  { label: '평균 평점', value: 4.9, suffix: '/5', type: 'float' },
];

const Hero = () => {
  const statsRef = useRef(null);

  useEffect(() => {
    const animateValue = (el, target, type = 'int', suffix = '') => {
      const duration = 1600;
      const start = performance.now();

      const frame = (now) => {
        const progress = Math.min((now - start) / duration, 1);
        const eased = 1 - Math.pow(1 - progress, 3);
        const current = target * eased;

        if (type === 'float') {
          el.textContent = `${current.toFixed(1)}${suffix}`;
        } else {
          el.textContent = `${Math.floor(current).toLocaleString()}${suffix}`;
        }

        if (progress < 1) requestAnimationFrame(frame);
      };

      requestAnimationFrame(frame);
    };

    const observer = new IntersectionObserver(([entry]) => {
      if (!entry.isIntersecting) return;
      entry.target.querySelectorAll('.metric-value').forEach((node, idx) => {
        animateValue(node, stats[idx].value, stats[idx].type, stats[idx].suffix);
      });
      observer.disconnect();
    }, { threshold: 0.35 });

    if (statsRef.current) observer.observe(statsRef.current);

    return () => observer.disconnect();
  }, []);

  return (
    <section className="hero section-shell" id="home">
      <div className="hero-light hero-light-1" />
      <div className="hero-light hero-light-2" />
      <div className="hero-light hero-light-3" />

      <div className="container hero-grid">
        <div className="hero-copy">
          <div className="section-badge">차세대 AI 감정 케어 플랫폼</div>

          <h1 className="hero-title">
            당신의 감정을 이해하는 가장
            <br />
            <span className="gradient-text">섬세한 AI 동반자</span>
          </h1>

          <p className="hero-description">
            메이티는 단순한 챗봇이 아니라, 사용자의 감정 흐름과 맥락을 이해하고
            먼저 반응하는 AI 감정 케어 경험을 제공합니다.
          </p>

          <div className="hero-actions">
            <button className="btn btn-primary">무료로 시작하기</button>
            <button className="btn btn-secondary">제품 데모 보기</button>
          </div>

          <div className="trust-row">
            <span>실시간 감정 분석</span>
            <span>개인화 상담 경험</span>
            <span>프라이버시 중심 설계</span>
          </div>
        </div>

        <div className="hero-visual-wrap">
          <div className="hero-panel">
            <div className="hero-panel-top">
              <div className="hero-ai-chip">
                <span className="live-dot" />
                Matey AI Live
              </div>
              <div className="hero-mini-tabs">
                <span className="active">Emotion</span>
                <span>Insight</span>
                <span>Memory</span>
              </div>
            </div>

            <div className="hero-conversation">
              <div className="msg ai">
                안녕하세요. 오늘 하루에서 가장 오래 남은 감정은 무엇이었나요?
              </div>
              <div className="msg user">
                괜찮은 척했는데, 사실 많이 지쳤어요.
              </div>
              <div className="msg ai">
                그 마음을 숨기느라 더 힘들었겠어요. 지금은 괜찮은 척하지 않아도 돼요.
              </div>
            </div>

            <div className="hero-insight-card">
              <div className="insight-label">AI Insight</div>
              <strong>최근 7일간 피로·불안 감정 상승 감지</strong>
              <p>대화 맥락과 활동 패턴을 바탕으로 회복 루틴을 제안합니다.</p>
            </div>

            <div className="floating-badge badge-left">개인화 추천</div>
            <div className="floating-badge badge-right">맥락 기반 이해</div>
          </div>

          <div className="hero-metrics" ref={statsRef}>
            {stats.map((item) => (
              <div key={item.label} className="metric-card">
                <div className="metric-value">0</div>
                <div className="metric-label">{item.label}</div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
